class Solution {
public:
    int maximumCostSubstring(string s, string chars, vector<int>& vals) {
        unordered_map<char, int> charVal;
        for (int i = 0; i < chars.size(); i++) {
            charVal[chars[i]] = vals[i];
        }
        int maxCost = 0;
        for (int i = 0; i < s.size(); i++) {
            int currCost = 0;
            for (int j = i; j < s.size(); j++) {
                char c = s[j];
                int val = charVal.count(c) ? charVal[c] : c - 'a' + 1;
                currCost += val;
                maxCost = max(maxCost, currCost);
            }
        }
        return maxCost;
    }
};
